- @ai-sdk/react: ^3.0.0-beta.99
- @ai-sdk/anthropic: ^3.0.0-beta.53
- @ai-sdk/google-vertex: ^4.0.0-beta.65
- @ai-sdk/provider-utils: ^4.0.0-beta.33

