vercel/ai#10560.body:
### Description

The AI SDK `streamText()` seems to swallow the `providerMetadata` when it throws `AI_InvalidToolInputError`

This causes the next downstream message turn to fail with a 400 Error from the Vertex API because `thought_signature` is required

seems related to https://github.com/vercel/ai/pull/10361

repro script:

```ts
import { createVertex } from '@ai-sdk/google-vertex';
import { streamText, tool } from 'ai';
import { z } from 'zod';

const PROJECT_ID = 'INSERT PROJECT ID HERE';
const LOCATION = 'global';

// Initialize Vertex provider
const vertex = createVertex({
    project: PROJECT_ID,
    location: LOCATION,
});

async function main() {
    console.log('=== Reproduction Script: Google Thought Signature Loss on Invalid Tool Input ===\n');

    const model = vertex('gemini-3-pro-preview');

    try {
        console.log('--- Turn 0: Verification (Reasoning Only) ---');
        const result0 = streamText({
            model,
            prompt: 'Think about why the sky is blue. Just explain your reasoning briefly.',
            providerOptions: { google: { thinkingConfig: { includeThoughts: true } } }
        });

        for await (const part of result0.fullStream) {
            // process.stdout.write(JSON.stringify(part, null, 2) + '\n');
            if (part.type === 'reasoning-delta' || part.type === 'text-delta') {
                process.stdout.write(part.text || '');
                // @ts-ignore
                if (part.providerMetadata?.google?.thoughtSignature) {
                    console.log(`\n✅ Turn 0: thoughtSignature PRESENT in reasoning-delta: ${part.providerMetadata?.google?.thoughtSignature}`);
                }
            }
        }
        console.log('\n--- Turn 0 Finished ---\n');

        console.log('Starting Turn 1: Forcing a Zod validation error...');

        // We need a tool that fails validation
        const result = streamText({
            model,
            tools: {
                test_tool: tool({
                    description: 'A test tool that will fail validation for specific inputs',
                    inputSchema: z.object({
                        query: z.string()
                            .describe('The query string')
                            .refine((val) => false, {
                                message: 'Intentionally failing validation',
                            }),
                    }),
                    execute: async ({ query }) => {
                        return `Executed with ${query}`;
                    },
                }),
            },
            // Prompt designed to trigger reasoning (thoughts) and then call the tool with invalid input
            prompt: 'First, explain why you are doing this. Then call the test_tool with the query "test" to test error handling.',
            providerOptions: {
                google: {
                    thinkingConfig: {
                        includeThoughts: true
                    }
                }
            }
        });

        for await (const part of result.fullStream) {
            if (part.type === 'reasoning-delta') {
                // Use 'text' instead of 'textDelta'
                process.stdout.write(part.text || '');

                // Check for signature in reasoning parts
                // @ts-ignore
                const metadata = part.providerMetadata;
                if (metadata?.google?.thoughtSignature) {
                    console.log('\n[Reasoning Delta] Found signature!');
                }
            }
            if (part.type === 'tool-call') {
                console.log('\n\n--- Tool Call Detected ---');
                console.log(`Tool Name: ${part.toolName}`);
                console.log(`Args: ${JSON.stringify(part.input)}`);

                const metadata = part.providerMetadata;
                console.log('Provider Metadata:', JSON.stringify(metadata, null, 2));

                const googleMetadata = metadata?.google;
                if (googleMetadata?.thoughtSignature) {
                    console.log('✅ thoughtSignature PRESENT');
                } else {
                    console.log('❌ thoughtSignature MISSING (This is the bug)');
                }

                console.log('--------------- FULL PART -------------');
                console.log(JSON.stringify(part, null, 2));
            }
            if (part.type === 'error') {
                console.log('\n\n--- Error Detected in Stream ---');
                // Check if it's the InvalidToolInputError we expect
                if (part.error && typeof part.error === 'object' && (part.error as any).name === 'AI_InvalidToolInputError') {
                    console.log('✅ Caught expected AI_InvalidToolInputError');
                }
                console.log(JSON.stringify(part.error, null, 2));
            }
        }

        console.log('\n\nTurn 1 Stream Finished.');

    } catch (error) {
        console.error('\nTop-level error caught:', error);
    }
}

main().catch(console.error);
```

