vercel/ai#11559.body:
### Description

When using the Vercel AI SDK with the Anthropic provider, tools defined with `strict: true` do not include the `strict` property in the request body sent to Anthropic's API when using Claude Haiku 4.5. This property is correctly included for Claude Sonnet 4.5 and Claude Opus 4.5.

This was initially correct, because structured outputs was not available for Claude Haiku 4.5. However, as of now, structured outputs are also available in Claude Haiku 4.5: https://platform.claude.com/docs/en/build-with-claude/structured-outputs

## Expected Behavior

When a tool is defined with `strict: true`, the tool definition in the request body sent to Anthropic should include the `strict: true` property:

```json
{
  "tools": [
    {
      "name": "testTool",
      "description": "A test tool with strict mode enabled",
      "input_schema": { ... },
      "strict": true
    }
  ]
}
```

## Actual Behavior

When using Claude Haiku 4.5, the `strict` property is missing from the tool definition in the request body:

```json
{
  "tools": [
    {
      "name": "testTool",
      "description": "A test tool with strict mode enabled",
      "input_schema": { ... }
      // strict: true is missing
    }
  ]
}
```

## Reproduction

Use the minimal reproduction example: 

```ts
import { createAnthropic } from "@ai-sdk/anthropic";
import {
  createAgentUIStreamResponse,
  ToolLoopAgent,
  tool,
  type UIMessage,
} from "ai";
import { z } from "zod";

const anthropic = createAnthropic({
  fetch: (requestInfo, requestInit) => {
    // Log the request body to inspect tool definitions
    if (requestInit?.body) {
      try {
        const body = JSON.parse(requestInit.body as string);
        console.log("=== Request Body ===");
        console.log(JSON.stringify(body, null, 2));
        console.log("===================\n");

        // Specifically log tools to check for strict property
        if (body.tools) {
          console.log("=== Tools in Request ===");
          body.tools.forEach(
            (
              tool: {
                name?: string;
                strict?: boolean;
                description?: string;
              },
              index: number,
            ) => {
              console.log(`Tool ${index + 1}:`, {
                name: tool.name,
                strict: tool.strict,
                description: tool.description?.substring(0, 50) + "...",
              });
            },
          );
          console.log("=======================\n");
        }
      } catch (e) {
        console.log("Could not parse request body:", e);
      }
    }

    return globalThis.fetch(requestInfo, requestInit);
  },
});

export async function POST(req: Request) {
  const { messages }: { messages: UIMessage[] } = await req.json();

  const agent = new ToolLoopAgent({
    model: anthropic("claude-haiku-4-5"),
    instructions: "You are a helpful assistant.",
    tools: {
      testTool: tool({
        description: "A test tool with strict mode enabled",
        inputSchema: z.object({
          message: z.string().describe("A message to process"),
        }),
        strict: true,
      }),
    },
    providerOptions: {
      anthropic: {
        structuredOutputMode: "outputFormat",
      },
    },
  });

  return createAgentUIStreamResponse({
    agent,
    uiMessages: messages,
  });
}
```
Make a POST request to the endpoint with messages

Check the console logs - the request body will show that `strict: true` is missing from the tools array

## Affected Models

- ❌ Claude Haiku 4.5 (bug present)
- ✅ Claude Sonnet 4.5 (works correctly)
