vercel/ai#11673.body:
### Description

When adding `inputExamples` to a tool that has a Zod schema with `.optional().default()` patterns or `.refine()` combined with dynamic enums, TypeScript inference breaks completely. The `execute` function's input parameter becomes `any` or `never`, and the tool call fails to compile.

### Case 1: Schema with `.optional().default()` and varying example shapes

```typescript
import { tool } from "ai";
import { z } from "zod/v4";

const BASH_INPUT = z.object({
  command: z.string(),
  timeout_ms: z.number().optional().default(60000),
  regex_filter: z.string().optional(),
  cwd: z.string(),
});

// This FAILS to compile
export const bash = tool({
  description: "Run shell commands",
  inputSchema: BASH_INPUT,
  inputExamples: [
    { input: { command: "ls -la", cwd: "/home/user" } },
    { input: { command: "npm build", timeout_ms: 300000, cwd: "/home/user" } },
    { input: { command: "npm test", regex_filter: "PASS|FAIL", cwd: "/home/user" } },
  ],
  execute: async ({ command, timeout_ms, regex_filter, cwd }) => {
    // TS Error: Binding element 'command' implicitly has an 'any' type
    return { command, timeout_ms, cwd };
  },
});
```

### Case 2: Schema with `.refine()` and dynamic enum

```typescript
import { tool } from "ai";
import { z } from "zod/v4";

const TEXT_TO_IMAGE_MODEL_IDS = ["model_a", "model_b", "model_c"] as const;

const IMAGE_GENERATE_INPUT = z
  .object({
    prompts: z.array(z.string()).min(1),
    names: z.array(z.string()).min(1),
    model: z.enum(TEXT_TO_IMAGE_MODEL_IDS).optional().default(TEXT_TO_IMAGE_MODEL_IDS[0]),
  })
  .refine((data) => data.prompts.length === data.names.length, {
    message: "prompts and names must be the same length",
  });

// This FAILS to compile
export const image_generate = tool({
  description: "Generate images",
  inputSchema: IMAGE_GENERATE_INPUT,
  inputExamples: [
    { input: { prompts: ["A sunset"], names: ["sunset"] } },
    { input: { prompts: ["A cat"], names: ["cat"], model: "model_b" } },
  ],
  execute: async (input) => {
    // TS Error: Parameter 'input' implicitly has an 'any' type
    return input;
  },
});
```

