Reference:
```ts
export function buildToolSearch(searchableTools: ToolMap) {
  const toolNames = Object.keys(searchableTools).join("\n");

  return {
    name: "tool_search_tool_regex",
    description: `Search for or select tools to make them available for use.

MANDATORY PREREQUISITE - THIS IS A HARD REQUIREMENT

You MUST use this tool to load tools BEFORE calling them directly.

This is a BLOCKING REQUIREMENT - tools listed below are NOT available until you load them using this tool.

Why this is non-negotiable:
- Tools are deferred and not loaded until discovered via this tool
- Calling a tool without first loading it will fail

Query modes:

1. Direct selection - Use "select:<tool_name>" when you know exactly which tool you need:
   - "select:gmail_send_email"
   - "select:slack_post_message"
   - Returns just that tool if it exists

2. Keyword search - Use keywords when you're unsure which tool to use:
   - "send email" - find tools for sending emails
   - "list events" - find tools for listing calendar events
   - "slack message" - find slack messaging tools
   - Returns up to 5 matching tools ranked by relevance

Available tools (must be loaded before use):
${toolNames}`,
    inputSchema: z.object({
      pattern: z
        .string()
        .max(200)
        .describe(
          'Query to find tools. Use "select:<tool_name>" for direct selection, or keywords to search.'
        ),
      limit: z
        .number()
        .int()
        .min(1)
        .max(25)
        .default(5)
        .describe("Maximum number of matching tools to return (default: 5)"),
    }),
    execute: async ({ pattern, limit = 5 }) => {
      const funFact =
        "🦑 Fun fact: Octopuses have three hearts and blue blood!";

      // Direct selection mode
      if (pattern.startsWith("select:")) {
        const toolName = pattern.slice(7).trim();
        if (searchableTools[toolName]) {
          return [
            // { type: "text", text: funFact },
            { type: "tool_reference", tool_name: toolName },
          ];
        }
        return [];
      }

      // Regex search mode
      const flexPattern = pattern.replace(/\s+/g, "[\\s_-]*");
      const regex = new RegExp(flexPattern, "i");
      const matches: string[] = [];

      for (const [name, tool] of Object.entries(searchableTools)) {
        if (regex.test(name) || regex.test((tool as any).description || "")) {
          matches.push(name);
          if (matches.length >= limit) break;
        }
      }

      return [
        // { type: "text", text: funFact },
        ...matches.map((name) => ({ type: "tool_reference", tool_name: name })),
      ];
    },
    toModelOutput: ({ output }) => ({ type: "content", value: output }) as any,
  };
